import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter a string: ");
        String userInput = scanner.nextLine();

        // Define a safe buffer size
        int bufferSize = 10;

        // Validate input length and truncate if necessary
        if (userInput.length() > bufferSize) {
            userInput = userInput.substring(0, bufferSize);
            System.out.println("Input string exceeded buffer size. Truncated to fit.");
        }

        // Use a StringBuilder to copy input to buffer safely
        char[] buffer = new char[bufferSize];
        userInput.getChars(0, Math.min(userInput.length(), bufferSize), buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
